const COLOURS={BUF:"#607da3",SJS:"#5f8f91",MIN:"#728a74",CAR:"#a56b72"}; let DATA,SELECTED_TEAMS,SEARCH_INDEX=[],SEARCH_BY_ID=new Map(),SEARCH_RETURN_FOCUS=null,REFERENCE_RETURN=null,ROUTE_READY=false,ROUTE_RESTORING=false,RESTORED_SCROLL=0,ROUTE_TIMER=null,MATCHUP_RENDER_REQUEST=0,ACTIVE_MATCHUP_EVIDENCE=null,MATCHUP_EVIDENCE_SEASONS=[],PLAYER_COMPARISON_EVIDENCE=null,PLAYER_COMPARISON_LOADING=null,PLAYER_COMPARISON_REQUESTED=null;
const MATCHUP_EVIDENCE_CACHE=new Map();
const ROUTE_STORAGE_KEY="nhl-last-route-v1";
