function renderGuide(){
  const categorySelect=el("guide-category");
  if(categorySelect.options.length===1)categorySelect.innerHTML+=GUIDE_CATEGORIES.map(x=>`<option value="${x}">${x}</option>`).join("");
  const q=(el("guide-search").value||"").trim().toLowerCase(),source=el("guide-source").value,category=categorySelect.value;
  const enriched=STAT_GUIDE.map(x=>({...x,...(GUIDE_DETAILS[x.term]||{}),category:guideCategory(x)}));
  const counts=Object.fromEntries(GUIDE_CATEGORIES.map(name=>[name,enriched.filter(row=>row.category===name).length]));
  el("guide-counts").innerHTML=`<span><strong>${STAT_GUIDE.length}</strong> terms</span><span><strong>${new Set(STAT_GUIDE.map(x=>x.source)).size}</strong> sources</span><span><strong>${GUIDE_CATEGORIES.length}</strong> topics</span><span><strong>${Object.keys(GUIDE_DETAILS).length}</strong> worked explanations</span>`;
  const landing=!q&&source==="ALL"&&category==="ALL",index=el("guide-category-index");
  index.hidden=!landing;
  index.innerHTML=landing?GUIDE_CATEGORIES.map(name=>`<button type="button" class="guide-category-button" data-guide-topic="${safeText(name)}"><strong>${safeText(name)}</strong><span>${safeText(guideUsedIn(name))}</span><b>${counts[name]} terms</b></button>`).join(""):"";
  const rows=enriched.filter(x=>{const searchable=[x.term,x.text,x.source,x.category,x.formula,x.read,x.caution,x.aliases].filter(Boolean).join(" ").toLowerCase();return(source==="ALL"||x.source===source)&&(category==="ALL"||x.category===category)&&(!q||searchable.includes(q))}).sort((a,b)=>a.term.localeCompare(b.term));
  const visible=landing?rows.filter(x=>x.category===GUIDE_CATEGORIES[0]):rows;
  const grouped=GUIDE_CATEGORIES.map(name=>[name,visible.filter(x=>x.category===name)]).filter(([,items])=>items.length);
  el("guide-results").innerHTML=grouped.map(([name,items])=>`<section class="guide-group"><div class="guide-group-heading"><h3>${landing?"Start here":safeText(name)}</h3><span>${items.length} ${items.length===1?"term":"terms"}</span></div><div class="guide-grid">${items.map(x=>{const deep=[x.formula&&`<p><span>Formula</span><strong>${safeText(x.formula)}</strong></p>`,x.read&&`<p><span>How to read it</span><strong>${safeText(x.read)}</strong></p>`,x.caution&&`<p><span>Keep in mind</span><strong>${safeText(x.caution)}</strong></p>`].filter(Boolean).join("");return`<article class="guide-card"><h4>${safeText(x.term)}</h4><p>${safeText(x.text)}</p>${deep?`<details class="guide-deep-dive"><summary>Formula and interpretation</summary>${deep}</details>`:""}<div class="guide-card-meta"><span class="source-tag">${safeText(x.source)}</span><span>Used in: ${guideUsedIn(x.category)}</span></div></article>`}).join("")}</div></section>`).join("")||`<div class="notice">No definitions match those filters. Try a broader topic or clear the search.</div>`;
  index.querySelectorAll("[data-guide-topic]").forEach(button=>button.onclick=()=>{categorySelect.value=button.dataset.guideTopic;renderGuide();categorySelect.focus()});
}

